// Parse Director Phase 2 Instructions for Database Creation
const directorResponse = $json;
const phase2Context = $('Setup Phase 2 Context').first().json.phase2Context;

// Extract instruction data
const instructionData = directorResponse.data;

if (!instructionData || !instructionData.instruction) {
  return [{
    instructionText: "Error: No valid Phase 2 instructions received from Director",
    error: true,
    task_id: "phase2_error_task"
  }];
}

// Build comprehensive Phase 2 instruction text
const instruction = instructionData.instruction;
let instructionText = '';

// Add Phase 2 header
instructionText += `# PHASE 2: DATABASE ITEM CREATION WORKFLOW\n\n`;
instructionText += `## WORKFLOW CONTEXT\n`;
instructionText += `- Session ID: ${phase2Context.sessionId}\n`;
instructionText += `- Current Phase: ${phase2Context.phase}\n`;
instructionText += `- Previous Context: ${instruction.parameters?.context_id}\n`;
instructionText += `- Operation Mode: ${instruction.parameters?.operation_mode}\n\n`;

// Add Phase 1 results summary
instructionText += `## PHASE 1 RESULTS SUMMARY\n`;
const categorizedIdeas = instruction.parameters?.categorized_ideas || [];
instructionText += `- Total Ideas Processed: ${categorizedIdeas.length}\n`;
const databaseCounts = categorizedIdeas.reduce((acc, idea) => {
  acc[idea.categorization.database] = (acc[idea.categorization.database] || 0) + 1;
  return acc;
}, {});
Object.entries(databaseCounts).forEach(([db, count]) => {
  instructionText += `- ${db.toUpperCase()} Items: ${count}\n`;
});
instructionText += '\n';

// Add primary objective
instructionText += `## PRIMARY OBJECTIVE\n`;
instructionText += `Create new database items from categorized ideas using generic Notion database endpoints.\n`;
instructionText += `Route each categorized idea to its assigned database and create properly structured items.\n\n`;

// Add target databases
if (instruction.parameters?.target_databases) {
  instructionText += `## TARGET DATABASES\n`;
  Object.entries(instruction.parameters.target_databases).forEach(([type, id]) => {
    const count = databaseCounts[type] || 0;
    instructionText += `- **${type.toUpperCase()}** (${id}): ${count} items to create\n`;
  });
  instructionText += '\n';
}

// Add detailed categorized ideas
instructionText += `## CATEGORIZED IDEAS FOR CREATION\n`;
categorizedIdeas.forEach((idea, index) => {
  instructionText += `### ${index + 1}. ${idea.title}\n`;
  instructionText += `- **Source ID**: ${idea.idea_id}\n`;
  instructionText += `- **Target Database**: ${idea.categorization.database} (${idea.categorization.database_id})\n`;
  instructionText += `- **Category**: ${idea.categorization.category}\n`;
  instructionText += `- **Priority**: ${idea.categorization.priority}\n`;
  instructionText += `- **Tags**: [${idea.categorization.tags.join(', ')}]\n`;
  instructionText += `- **Content**: ${idea.original_content}\n\n`;
});

// Add execution requirements
instructionText += `## EXECUTION REQUIREMENTS\n`;
instructionText += `1. **Use Generic Database Endpoints**: Use \`/api/databases/{databaseId}/pages\` for all operations\n`;
instructionText += `2. **Auto-Detect Database Schemas**: Call \`/api/databases/{databaseId}/schema\` first\n`;
instructionText += `3. **Create New Items**: Use POST to create new pages in target databases\n`;
instructionText += `4. **Update Source Ideas**: Set original ideas to 'Done' status after creation\n`;
instructionText += `5. **Maintain Data Integrity**: Preserve all categorization metadata\n\n`;

// Add detailed execution steps
instructionText += `## DETAILED EXECUTION STEPS\n`;
instructionText += `For each categorized idea:\n`;
instructionText += `1. **Get Database Schema**: \`GET /api/databases/{database_id}/schema\`\n`;
instructionText += `2. **Create Database Item**: \`POST /api/databases/{database_id}/pages\` with:\n`;
instructionText += `   - Title/Name: Use idea title\n`;
instructionText += `   - Content/Description: Use original content\n`;
instructionText += `   - Category/Type: Use categorization.category\n`;
instructionText += `   - Priority: Use categorization.priority\n`;
instructionText += `   - Tags: Use categorization.tags\n`;
instructionText += `   - Source: Reference original idea_id\n`;
instructionText += `3. **Update Source Idea**: \`PUT /api/ideas/{idea_id}\` status='Done'\n`;
instructionText += `4. **Log Operation**: Record success/failure for each creation\n\n`;

// Add expected output format
instructionText += `## EXPECTED OUTPUT FORMAT\n`;
instructionText += `Return comprehensive results for Phase 2:\n`;
instructionText += `{\n`;
instructionText += `  \"agent_id\": \"notion\",\n`;
instructionText += `  \"task_id\": \"${instructionData.task_id}\",\n`;
instructionText += `  \"phase\": \"database_creation_complete\",\n`;
instructionText += `  \"timestamp\": \"ISO timestamp\",\n`;
instructionText += `  \"execution_time_ms\": \"duration\",\n`;
instructionText += `  \"results\": {\n`;
instructionText += `    \"database_items_created\": [\n`;
instructionText += `      {\n`;
instructionText += `        \"source_idea_id\": \"original_id\",\n`;
instructionText += `        \"new_item_id\": \"created_page_id\",\n`;
instructionText += `        \"database_type\": \"projects|knowledge|journal\",\n`;
instructionText += `        \"database_id\": \"target_db_id\",\n`;
instructionText += `        \"title\": \"item_title\",\n`;
instructionText += `        \"creation_status\": \"success|failed\",\n`;
instructionText += `        \"error_message\": \"if failed\"\n`;
instructionText += `      }\n`;
instructionText += `    ],\n`;
instructionText += `    \"source_ideas_updated\": [\n`;
instructionText += `      {\n`;
instructionText += `        \"idea_id\": \"original_id\",\n`;
instructionText += `        \"status_updated_to\": \"Done\",\n`;
instructionText += `        \"update_status\": \"success|failed\"\n`;
instructionText += `      }\n`;
instructionText += `    ],\n`;
instructionText += `    \"summary\": {\n`;
instructionText += `      \"total_ideas_processed\": ${categorizedIdeas.length},\n`;
instructionText += `      \"successful_creations\": \"number\",\n`;
instructionText += `      \"failed_creations\": \"number\",\n`;
instructionText += `      \"projects_created\": \"number\",\n`;
instructionText += `      \"knowledge_created\": \"number\",\n`;
instructionText += `      \"journal_created\": \"number\",\n`;
instructionText += `      \"source_ideas_completed\": \"number\"\n`;
instructionText += `    }\n`;
instructionText += `  },\n`;
instructionText += `  \"status\": {\n`;
instructionText += `    \"success\": \"boolean\",\n`;
instructionText += `    \"errors\": [\"array of errors\"],\n`;
instructionText += `    \"next_phase\": \"workflow_complete\"\n`;
instructionText += `  },\n`;
instructionText += `  \"performance_metrics\": {\n`;
instructionText += `    \"database_schemas_fetched\": \"number\",\n`;
instructionText += `    \"api_calls_made\": \"number\",\n`;
instructionText += `    \"average_creation_time_ms\": \"number\"\n`;
instructionText += `  }\n`;
instructionText += `}\n\n`;

instructionText += `## CRITICAL REMINDERS\n`;
instructionText += `- Use GENERIC database endpoints (/api/databases/{id}/...) NOT legacy idea endpoints\n`;
instructionText += `- Fetch schema first to understand each database's structure\n`;
instructionText += `- Create items with ALL available relevant properties\n`;
instructionText += `- Update original ideas to 'Done' status after successful creation\n`;
instructionText += `- Log detailed success/failure information for Director context\n\n`;

instructionText += `**BEGIN PHASE 2 DATABASE CREATION EXECUTION NOW**\n`;

return [{
  instructionText,
  task_id: instructionData.task_id,
  phase: 'database_creation',
  categorized_ideas: categorizedIdeas,
  target_databases: instruction.parameters?.target_databases,
  context_id: instruction.parameters?.context_id,
  directorResponse: instructionData
}];

// Process Phase 2 Results - Database Creation Complete
const agentOutput = $json;
const phase2Context = $('Parse Phase 2 Instructions').first().json;

// Parse agent output
let phase2Results;
try {
  const outputText = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);
  console.log('Phase 2 Agent Output:', outputText.substring(0, 500));

  const jsonMatch = outputText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    phase2Results = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback structure for Phase 2
    phase2Results = {
      agent_id: 'notion',
      task_id: phase2Context.task_id || 'phase2_task',
      phase: 'database_creation_complete',
      timestamp: new Date().toISOString(),
      execution_time_ms: Date.now() - new Date($('Setup Phase 2 Context').first().json.phase2Context.startTime).getTime(),
      results: {
        database_items_created: [],
        source_ideas_updated: [],
        summary: {
          total_ideas_processed: phase2Context.categorized_ideas?.length || 0,
          successful_creations: 0,
          failed_creations: 0,
          projects_created: 0,
          knowledge_created: 0,
          journal_created: 0,
          source_ideas_completed: 0
        }
      },
      status: {
        success: true,
        errors: [],
        next_phase: 'workflow_complete'
      },
      performance_metrics: {
        database_schemas_fetched: 0,
        api_calls_made: 0,
        average_creation_time_ms: 0
      }
    };
  }
} catch (error) {
  console.error('Error parsing Phase 2 results:', error.message);
  phase2Results = {
    agent_id: 'notion',
    task_id: 'phase2_error',
    phase: 'database_creation_error',
    timestamp: new Date().toISOString(),
    error: error.message,
    status: { success: false, errors: [error.message], next_phase: 'error_review' }
  };
}

// Calculate comprehensive metrics
const totalExecutionTime = Date.now() - new Date($('Setup Phase 2 Context').first().json.phase2Context.startTime).getTime();
const originalIdeasCount = phase2Context.categorized_ideas?.length || 0;

// Analyze creation results by database type
const databaseBreakdown = {
  projects: { created: 0, failed: 0 },
  knowledge: { created: 0, failed: 0 },
  journal: { created: 0, failed: 0 }
};

if (phase2Results.results?.database_items_created) {
  phase2Results.results.database_items_created.forEach(item => {
    if (item.database_type && databaseBreakdown[item.database_type]) {
      if (item.creation_status === 'success') {
        databaseBreakdown[item.database_type].created++;
      } else {
        databaseBreakdown[item.database_type].failed++;
      }
    }
  });
}

// Create workflow completion summary
const workflowSummary = {
  phase2_complete: true,
  workflow_complete: phase2Results.status?.next_phase === 'workflow_complete',
  total_execution_time_ms: totalExecutionTime,
  phase1_results: {
    ideas_categorized: originalIdeasCount,
    categories_assigned: ['projects', 'knowledge', 'journal']
  },
  phase2_results: {
    database_items_created: phase2Results.results?.database_items_created?.length || 0,
    source_ideas_updated: phase2Results.results?.source_ideas_updated?.length || 0,
    creation_success_rate: originalIdeasCount > 0 ? 
      (phase2Results.results?.summary?.successful_creations || 0) / originalIdeasCount : 0
  },
  database_breakdown: databaseBreakdown,
  performance_analysis: {
    avg_time_per_creation: phase2Results.performance_metrics?.average_creation_time_ms || 0,
    total_api_calls: phase2Results.performance_metrics?.api_calls_made || 0,
    schemas_fetched: phase2Results.performance_metrics?.database_schemas_fetched || 0
  }
};

// Create Director context update payload
const directorContextUpdate = {
  context_id: phase2Context.context_id,
  phase: 'workflow_complete',
  agent_response: phase2Results,
  workflow_summary: workflowSummary,
  timestamp: new Date().toISOString()
};

// Final output
return [{
  phase2Complete: true,
  workflowResults: {
    phase1_categorization: {
      ideas_processed: originalIdeasCount,
      categorization_complete: true
    },
    phase2_creation: {
      items_created: phase2Results.results?.database_items_created?.length || 0,
      success_rate: workflowSummary.phase2_results.creation_success_rate,
      database_breakdown: databaseBreakdown
    },
    overall_success: phase2Results.status?.success && workflowSummary.workflow_complete,
    total_time_ms: totalExecutionTime
  },
  directorContextUpdate,
  phase2Results,
  rawAgentOutput: agentOutput.output || agentOutput.text || 'No output captured',
  debugInfo: {
    original_ideas_count: originalIdeasCount,
    context_id: phase2Context.context_id,
    task_id: phase2Context.task_id,
    databases_targeted: Object.keys(phase2Context.target_databases || {})
  }
}];
